import{_ as s,c as t,o as a,a5 as i}from"./chunks/framework.CgT1UzWm.js";const k=JSON.parse('{"title":"TEST @teardown Annotation","titleTemplate":"NpgsqlRest","description":"Run named teardown steps after an individual SQL test file, always. Test-runner (--test) test files only.","frontmatter":{"outline":[2,3],"title":"TEST @teardown Annotation","titleTemplate":"NpgsqlRest","description":"Run named teardown steps after an individual SQL test file, always. Test-runner (--test) test files only.","head":[["meta",{"name":"keywords","content":"npgsqlrest test teardown, per-file teardown, test cleanup, sql test runner annotations"}],["meta",{"property":"og:title","content":"NpgsqlRest TEST @teardown Annotation"}],["meta",{"property":"og:description","content":"Run named teardown steps after an individual SQL test file, always."}],["meta",{"property":"og:type","content":"article"}]]},"headers":[],"relativePath":"annotations/test-teardown.md","filePath":"annotations/test-teardown.md"}'),n={name:"annotations/test-teardown.md"};function l(r,e,o,p,d,h){return a(),t("div",null,e[0]||(e[0]=[i(`<h1 id="test-teardown" tabindex="-1">TEST @teardown <a class="header-anchor" href="#test-teardown" aria-label="Permalink to &quot;TEST @teardown&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Test files only</p><p>This annotation applies <strong>only to test files</strong> run by the <a href="./../guide/testing.html">SQL test runner</a> (<code>npgsqlrest --test</code>). It has no meaning in endpoint SQL files or routine comments.</p></div><p>Run one or more <strong>named steps</strong> (from the <a href="./../config/test-runner.html#steps"><code>TestRunner.Steps</code></a> registry) <strong>after this test file</strong> — <strong>always</strong>, best-effort, even when the file failed or errored.</p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h2><p>Placed in the file&#39;s <strong>header</strong> — the leading <code>--</code> line comments before the first SQL statement or HTTP block:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- @teardown StepName [StepName ...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><ul><li>Names may be <strong>whitespace- or comma-separated</strong>; the annotation is <strong>repeatable</strong>; steps run in the <strong>order written</strong>.</li><li>Every name must exist in the <code>TestRunner.Steps</code> registry.</li><li>Runs after the file&#39;s own connection is disposed, so it can safely <code>drop database ... with (force)</code> on an admin connection.</li></ul><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- @setup CreateIsolatedDb</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- @teardown DropIsolatedDb</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- @connection Isolated</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">begin</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">insert into</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> users (</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">name</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">) </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">values</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> (</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;fixture&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">);</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">select</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> count</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">(</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">*</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">) </span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">=</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> 1</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">, </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;fixture inserted in the private clone&#39;</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> from</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> users;</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">rollback</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div></details><p>Even if the assertion fails — or the file errors halfway — <code>DropIsolatedDb</code> still runs, so the per-file database never leaks.</p><h2 id="ordering" tabindex="-1">Ordering <a class="header-anchor" href="#ordering" aria-label="Permalink to &quot;Ordering&quot;">​</a></h2><p>For one test file the lifecycle is:</p><ol><li>per-file <code>@setup</code> steps (in written order)</li><li>the file body, on its own non-pooled connection</li><li>connection disposed</li><li>per-file <code>@teardown</code> steps (in written order, always)</li></ol><p>The run-level <a href="./../config/test-runner.html#setup-and-teardown"><code>TestRunner.Setup</code>/<code>Teardown</code></a> wrap the <em>whole run</em> outside of this.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./test-setup.html">TEST @setup</a> — the mirror, runs before the file</li><li><a href="./test-connection.html">TEST @connection</a> — run the file on another connection</li><li><a href="./../config/test-runner.html">Test Runner configuration</a></li><li><a href="./../guide/testing.html">Testing Guide</a></li></ul>`,16)]))}const u=s(n,[["render",l]]);export{k as __pageData,u as default};
